"use client";

import { Menu as MenuRoot, type MenuProps } from "./menu";
import { MenuItem, type MenuItemProps } from "./menu-item";
import { MenuDivider, type MenuDividerProps } from "./menu-divider";

const Menu = Object.assign(MenuRoot, {
  Item: MenuItem,
  Divider: MenuDivider,
});

export { Menu, type MenuProps };
export { MenuItem, type MenuItemProps };
export { MenuDivider, type MenuDividerProps };

"use client";

import {
  type ReactNode,
  type KeyboardEvent,
  type ComponentPropsWithRef,
  useId,
  useMemo,
} from "react";
import { collectListboxItems, getEncodedListboxItemId, useListbox } from "@/hooks/use-listbox";
import { cn } from "@/lib/utils";
import { MenuContext, type MenuContextValue } from "./menu-context";
import { MenuItem } from "./menu-item";

export interface MenuProps
  extends Omit<ComponentPropsWithRef<"div">, "children" | "onKeyDown" | "onSelect"> {
  selectedId?: string | null;
  defaultSelectedId?: string | null;
  highlighted?: string | null;
  defaultHighlighted?: string | null;
  onSelect?: (id: string) => void;
  onHighlightChange?: (value: string | null) => void;
  onClose?: () => void;
  variant?: "default" | "hub";
  wrap?: boolean;
  children: ReactNode;
  autoFocus?: boolean;
  onKeyDown?: (event: KeyboardEvent) => void;
}

export function Menu({
  selectedId: controlledSelectedId,
  defaultSelectedId = null,
  highlighted: controlledHighlighted,
  defaultHighlighted = null,
  onSelect,
  onHighlightChange,
  onClose,
  variant = "default",
  wrap = true,
  className,
  "aria-label": ariaLabel,
  autoFocus,
  children,
  onKeyDown,
  ref,
  ...rootProps
}: MenuProps) {
  const idPrefix = useId();
  const selectionEnabled = controlledSelectedId !== undefined || defaultSelectedId !== null;
  const itemRole = selectionEnabled ? "menuitemradio" : "menuitem";
  const items = useMemo(() => collectListboxItems(children, MenuItem), [children]);

  const {
    selectedId,
    highlighted,
    handleItemActivate,
    handleItemHighlight,
    getContainerProps,
  } = useListbox({
    selectedId: selectionEnabled ? controlledSelectedId : null,
    defaultSelectedId: selectionEnabled ? defaultSelectedId : null,
    highlighted: controlledHighlighted,
    defaultHighlighted,
    onSelect,
    onHighlightChange,
    wrap,
    idPrefix,
    onKeyDown: (e: KeyboardEvent) => {
      if (e.key === "Escape") onClose?.();
      if (e.key === "Tab") onClose?.();
      onKeyDown?.(e);
    },
    role: "menu",
    itemRole,
    typeahead: true,
    autoFocus,
    items,
    getItemId: getEncodedListboxItemId,
  });

  const contextValue: MenuContextValue = useMemo(
    () => ({
      selectedId,
      highlighted,
      activate: handleItemActivate,
      highlight: handleItemHighlight,
      variant,
      idPrefix,
      itemRole,
    }),
    [selectedId, highlighted, handleItemActivate, handleItemHighlight, variant, idPrefix, itemRole],
  );

  return (
    <MenuContext value={contextValue}>
      <div
        {...rootProps}
        {...getContainerProps(ref)}
        aria-label={ariaLabel}
        className={cn("w-full relative outline-none", className)}
      >
        {children}
      </div>
    </MenuContext>
  );
}

"use client";

import type { ComponentPropsWithRef, FocusEvent, MouseEvent, ReactNode, Ref } from "react";
import { cva } from "class-variance-authority";
import { getEncodedListboxItemId } from "@/hooks/use-listbox";
import { cn } from "@/lib/utils";
import { useMenuContext } from "./menu-context";

const INDICATOR_ACTIVE = "\u258C";
const INDICATOR_IDLE = ">";

function MenuItemIndicator({ isFocused, isSelected, className }: { isFocused: boolean; isSelected: boolean; className?: string }) {
  return (
    <span
      aria-hidden="true"
      className={cn(
        "pr-4 shrink-0 inline-flex w-5 items-center justify-center self-center leading-none relative -top-[2px]",
        className,
      )}
    >
      {isFocused || isSelected ? INDICATOR_ACTIVE : INDICATOR_IDLE}
    </span>
  );
}

interface DefaultItemLayoutProps {
  isFocused: boolean;
  isSelected: boolean;
  isDanger: boolean;
  hotkey?: number | string;
  children: ReactNode;
}

function DefaultItemLayout({ isFocused, isSelected, isDanger, hotkey, children }: DefaultItemLayoutProps) {
  const idleColor = isDanger ? "text-destructive" : "text-foreground";
  const isEmphasized = isFocused || isSelected;

  return (
    <>
      <MenuItemIndicator
        isFocused={isFocused}
        isSelected={isSelected}
        className={isEmphasized ? undefined : cn("transition-opacity opacity-0 group-hover:opacity-100", idleColor)}
      />
      {hotkey !== undefined && (
        <span
          aria-hidden="true"
          className={isEmphasized ? "mr-4 shrink-0" : cn("mr-4 shrink-0 group-hover:text-foreground", idleColor)}
        >
          [{hotkey}]
        </span>
      )}
      <span className={cn("tracking-wide", !isEmphasized && !isDanger && "group-hover:text-foreground")}>
        {children}
      </span>
    </>
  );
}

interface HubItemLayoutProps {
  isFocused: boolean;
  isSelected: boolean;
  value?: ReactNode;
  valueClassName: string;
  children: ReactNode;
}

function HubItemLayout({
  isFocused,
  isSelected,
  value,
  valueClassName,
  children,
}: HubItemLayoutProps) {
  const isEmphasized = isFocused || isSelected;

  return (
    <>
      <div className="flex items-center">
        <MenuItemIndicator
          isFocused={isFocused}
          isSelected={isSelected}
          className={
            !isEmphasized ? "text-foreground opacity-0 group-hover:opacity-100 transition-opacity" : undefined
          }
        />
        <span className={isEmphasized ? undefined : "font-medium group-hover:text-foreground"}>
          {children}
        </span>
      </div>
      {value !== undefined && value !== null && <div className={valueClassName}>{value}</div>}
    </>
  );
}

type ItemState = "normal" | "focused" | "selected" | "disabled" | "disabledFocused";

function getItemState(disabled: boolean, isFocused: boolean, isSelected: boolean): ItemState {
  if (disabled && isFocused) return "disabledFocused";
  if (disabled) return "disabled";
  if (isFocused) return "focused";
  if (isSelected) return "selected";
  return "normal";
}

const menuItemBase = cva("cursor-pointer w-full transition-colors", {
  variants: {
    menuVariant: {
      default: "px-4 py-3 flex items-center font-mono duration-75",
      hub: "px-4 py-4 flex justify-between items-center text-sm border-b border-border last:border-b-0",
    },
      state: {
        normal: "hover:bg-secondary group",
        focused: "font-bold",
        selected: "font-bold group",
        disabled: "opacity-50 cursor-not-allowed",
        disabledFocused: "opacity-60 cursor-not-allowed bg-secondary text-foreground",
      },
    colorVariant: {
      default: "",
      danger: "",
    },
  },
  compoundVariants: [
    { state: "focused", menuVariant: "hub", class: "shadow-[inset_0_0_15px_rgba(0,0,0,0.1)]" },
    { state: "disabled", menuVariant: "default", class: "hover:bg-transparent" },
    { state: "disabledFocused", menuVariant: "hub", class: "shadow-[inset_0_0_15px_rgba(0,0,0,0.1)]" },
    { colorVariant: "danger", state: "focused", class: "bg-destructive text-destructive-foreground" },
    { colorVariant: "default", state: "focused", class: "bg-primary text-primary-foreground" },
    { colorVariant: "danger", state: "selected", class: "bg-destructive text-destructive-foreground" },
    { colorVariant: "default", state: "selected", class: "bg-primary text-primary-foreground" },
    { colorVariant: "danger", state: "normal", menuVariant: "default", class: "text-destructive" },
  ],
  defaultVariants: { menuVariant: "default", state: "normal", colorVariant: "default" },
});

const menuItemValue = cva("font-mono text-xs", {
  variants: {
    valueVariant: {
      default: "",
      success: "",
      "success-badge": "border px-2 py-0.5 rounded",
      muted: "",
    },
    focused: {
      true: "uppercase tracking-wide",
      false: "",
    },
    active: {
      true: "",
      false: "",
    },
  },
  compoundVariants: [
    {
      valueVariant: "default",
      active: false,
      class: "text-muted-foreground",
    },
    {
      valueVariant: "success",
      active: false,
      class: "text-success",
    },
    {
      valueVariant: "success-badge",
      active: false,
      class: "text-success border-success/30 bg-success/10",
    },
    {
      valueVariant: "muted",
      active: false,
      class: "text-muted-foreground/60",
    },
    {
      valueVariant: "default",
      active: true,
      class: "text-current",
    },
    {
      valueVariant: "success",
      active: true,
      class: "text-current",
    },
    {
      valueVariant: "muted",
      active: true,
      class: "text-current",
    },
    {
      valueVariant: "success-badge",
      active: true,
      class: "border-success bg-success text-success-foreground",
    },
  ],
  defaultVariants: { valueVariant: "default", focused: false, active: false },
});

export interface MenuItemProps
  extends Omit<
    ComponentPropsWithRef<"div">,
    "id" | "children" | "role" | "aria-checked" | "aria-disabled" | "data-value" | "ref"
  > {
  id: string;
  disabled?: boolean;
  variant?: "default" | "danger";
  hotkey?: number | string;
  value?: ReactNode;
  valueVariant?: "default" | "success" | "success-badge" | "muted";
  children: ReactNode;
  ref?: Ref<HTMLDivElement>;
}

export function MenuItem({
  id,
  disabled = false,
  variant = "default",
  hotkey,
  value,
  valueVariant = "default",
  children,
  className,
  ref,
  onClick,
  onFocus,
  onMouseDown,
  ...rootProps
}: MenuItemProps) {
  const { selectedId, highlighted, activate, highlight, variant: menuVariant, idPrefix, itemRole } =
    useMenuContext();

  const isSelected = !disabled && selectedId === id;
  const isFocused = highlighted === id;
  const isActive = !disabled && (isFocused || isSelected);
  const isDanger = variant === "danger";
  const isHub = menuVariant === "hub";
  const state = getItemState(disabled, isFocused, isSelected);
  const itemId = getEncodedListboxItemId(idPrefix, id);

  const handleClick = (event: MouseEvent<HTMLDivElement>) => {
    onClick?.(event);
    if (event.defaultPrevented || disabled) return;
    activate(id);
  };

  const handleFocus = (event: FocusEvent<HTMLDivElement>) => {
    onFocus?.(event);
    if (event.defaultPrevented || disabled) return;
    highlight(id);
  };

  const handleMouseDown = (event: MouseEvent<HTMLDivElement>) => {
    onMouseDown?.(event);
    if (event.defaultPrevented) return;
    if (disabled) event.preventDefault();
  };

  return (
    <div
      {...rootProps}
      ref={ref}
      id={itemId}
      role={itemRole}
      data-value={id}
      data-active={isActive || undefined}
      data-focus={isFocused || undefined}
      aria-checked={itemRole === "menuitemradio" ? isSelected : undefined}
      aria-disabled={disabled || undefined}
      data-state={isSelected ? "selected" : "unselected"}
      onMouseDown={handleMouseDown}
      onClick={handleClick}
      onFocus={handleFocus}
      className={cn(menuItemBase({ menuVariant, state, colorVariant: variant }), className)}
    >
      {isHub ? (
        <HubItemLayout
          isFocused={isFocused}
          isSelected={isSelected}
          value={value}
          valueClassName={menuItemValue({ valueVariant, focused: isActive, active: isActive })}
        >
          {children}
        </HubItemLayout>
      ) : (
        <DefaultItemLayout isFocused={isFocused} isSelected={isSelected} isDanger={isDanger} hotkey={hotkey}>
          {children}
        </DefaultItemLayout>
      )}
    </div>
  );
}

"use client";

import { cn } from "@/lib/utils";

export interface MenuDividerProps {
  className?: string;
}

export function MenuDivider({ className }: MenuDividerProps) {
  return (
    <div
      role="separator"
      aria-orientation="horizontal"
      className={cn("my-1 border-t border-border mx-4 opacity-50", className)}
    />
  );
}

"use client";

import { createContext, useContext } from "react";

export interface MenuContextValue {
  selectedId: string | null;
  highlighted: string | null;
  activate: (id: string) => void;
  highlight: (id: string) => void;
  variant: "default" | "hub";
  idPrefix: string;
  itemRole: "menuitem" | "menuitemradio";
}

export const MenuContext = createContext<MenuContextValue | undefined>(undefined);

export function useMenuContext(): MenuContextValue {
  const context = useContext(MenuContext);
  if (context === undefined) {
    throw new Error("Menu parts must be used within a Menu");
  }
  return context;
}
